feed:
  {{ sitename }}
  {{ siteroot }}/


    Ayu

  {{*
    local e = entries[1]
    local year, month = table.unpack(e)
    local log = render(string.format('items/revlog/%d.%02d.txt', year, month))
    local y, m, d, h = table.unpack(split(log.timestamp, '.'))
    return os.date('!%FT%TZ', os.time({ year = y, month = m, day = d, hour = h }))
  }}
